const projeto = $('Limit — 1 projeto').item.json;
const arquivos = $input.all().map(i => i.json);
const lista = arquivos.map(a => ({ nome: a.nome, tipo: a.tipo, drive_file_id: a.drive_file_id }));
const foto = lista.find(a => a.tipo === 'foto') || null;

return [{
  json: {
    projeto_id: projeto.id,
    brief: projeto.brief || '',
    tipo_entrada: projeto.tipo_entrada,
    plano: projeto.plano,
    arquivos: lista,
    foto_drive_id: foto ? foto.drive_file_id : null,
    foto_nome: foto ? foto.nome : null,
    foto_mime: 'image/jpeg'
  }
}];

const ctx = $('Code — montar contexto').item.json;
const bin = items[0].binary && items[0].binary.data;
let mediaType = (bin && bin.mimeType) ? bin.mimeType : ctx.foto_mime;
if (mediaType === 'image/jpg') mediaType = 'image/jpeg';

let imageBlock = null;
if (bin) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  imageBlock = {
    type: 'image',
    source: { type: 'base64', media_type: mediaType, data: buffer.toString('base64') }
  };
}

return [{ json: { ...ctx, imageBlock } }];

const projetoId = $('Code — prompt Copywriter').item.json.projeto_id;
const resp = $input.first().json;

const text = (resp.content || [])
  .filter(b => b.type === 'text')
  .map(b => b.text)
  .join('\n')
  .trim();

let parsed;
try {
  const cleaned = text.replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    projeto_id: projetoId,
    agente: 'copywriter',
    status: 'erro',
    resultado: { conteudos: [] },
    qualidade: 0,
    problemas: ['JSON inválido: ' + e.message, text.slice(0, 500)],
    proximo_agente: null
  };
}

parsed.projeto_id = parsed.projeto_id || projetoId;
parsed.agente = 'copywriter';

const raw = String(parsed.status || '').toLowerCase().trim();
const okAliases = new Set(['ok', 'completo', 'complete', 'success', 'sucesso', 'done']);
const reviewAliases = new Set(['precisa_revisao', 'revisao', 'review', 'needs_review']);
if (okAliases.has(raw)) parsed.status = 'ok';
else if (reviewAliases.has(raw)) parsed.status = 'precisa_revisao';
else if (['erro', 'error', 'fail', 'failed'].includes(raw)) parsed.status = 'erro';
else if (parsed.resultado && Array.isArray(parsed.resultado.conteudos) && parsed.resultado.conteudos.length) {
  parsed.status = 'ok';
} else {
  parsed.status = 'erro';
}

if (parsed.qualidade && typeof parsed.qualidade === 'object') {
  const n = Number(parsed.qualidade.nota);
  parsed.qualidade = Number.isFinite(n) ? Math.round(n * (n <= 10 ? 10 : 1)) : 0;
}

const estado = parsed.status === 'ok' ? 'escrito' : 'erro';
const conteudos = (parsed.resultado && parsed.resultado.conteudos) ? parsed.resultado.conteudos : [];

return [{
  json: {
    projeto_id: projetoId,
    estado,
    saida: parsed,
    conteudos,
    status_agente: parsed.status,
    mensagem_log: parsed.status === 'ok'
      ? ('Copywriter: ' + conteudos.length + ' texto(s)-mãe')
      : ('Copywriter: ' + parsed.status)
  }
}];

const base = $input.first().json;
const rows = [];

if (base.status_agente === 'ok' && base.conteudos.length) {
  for (const c of base.conteudos) {
    rows.push({
      json: {
        projeto_id: base.projeto_id,
        estado: base.estado,
        status_agente: base.status_agente,
        mensagem_log: base.mensagem_log,
        saida: base.saida,
        insert_mode: 'conteudo',
        agente: 'copywriter',
        tipo: c.tipo || 'post_instagram',
        conteudo: c,
        versao_prompt: 'copywriter-v0.2'
      }
    });
  }
}

// always one update+log marker at end
rows.push({
  json: {
    projeto_id: base.projeto_id,
    estado: base.estado,
    status_agente: base.status_agente,
    mensagem_log: base.mensagem_log,
    saida: base.saida,
    insert_mode: 'finalizar',
    agente: 'copywriter',
    tipo: 'lote',
    conteudo: base.saida,
    versao_prompt: 'copywriter-v0.2'
  }
});

return rows;
